// Reimagine result shows the bolder redesign, distinct from the Match page.
// Source: ~/Desktop/dust-1.png. Regenerate:
//   sips -s format jpeg -s formatOptions 82 dust-1.png --out x.jpg; base64 -i x.jpg
export const REIMAGINE_PAGE_IMAGE = 'data:image/jpeg;base64,';
